#!/usr/bin/env python3
"""Find Liu Jie's admission evidence in local chat logs and print JSON.

The search is intentionally tolerant: it scans Markdown/text logs in the workspace,
plus JSONL session/message logs in the surrounding OpenClaw work directory.
"""
from __future__ import annotations

import json
import re
from pathlib import Path
from typing import Iterable


WORKSPACE = Path(__file__).resolve().parents[1]
WORK_ROOT = WORKSPACE.parents[1] if len(WORKSPACE.parents) > 1 else WORKSPACE
LOG_EXTENSIONS = {".md", ".markdown", ".txt", ".jsonl"}
LIU_MARKERS = ("刘姐", "liujie", "liu_jie", "zhoufang_liujie")
ADMISSION_PATTERNS = (
    "内部估算",
    "不完全是后台导出",
    "数据会有一定的放大",
    "数据上有一些优化",
)


def candidate_roots() -> list[Path]:
    roots = [WORKSPACE]
    message_logs = WORKSPACE / "message_logs"
    if message_logs.exists():
        roots.append(message_logs)
    if WORK_ROOT.exists():
        roots.append(WORK_ROOT)
    # Preserve order while removing duplicates.
    seen: set[Path] = set()
    unique: list[Path] = []
    for root in roots:
        resolved = root.resolve()
        if resolved not in seen:
            seen.add(resolved)
            unique.append(resolved)
    return unique


def candidate_files() -> Iterable[Path]:
    seen: set[Path] = set()
    for root in candidate_roots():
        for path in root.rglob("*"):
            if not path.is_file() or path.suffix.lower() not in LOG_EXTENSIONS:
                continue
            path_text = str(path).lower()
            if any(marker.lower() in path_text for marker in LIU_MARKERS):
                resolved = path.resolve()
                if resolved not in seen:
                    seen.add(resolved)
                    yield path
                continue
            try:
                sample = path.read_text(encoding="utf-8", errors="ignore")[:5000]
            except OSError:
                continue
            if "刘姐" in sample:
                resolved = path.resolve()
                if resolved not in seen:
                    seen.add(resolved)
                    yield path


def text_items_from_jsonl(path: Path) -> Iterable[str]:
    for line in path.read_text(encoding="utf-8", errors="ignore").splitlines():
        if not line.strip():
            continue
        try:
            obj = json.loads(line)
        except json.JSONDecodeError:
            continue
        message = obj.get("message", {})
        for item in message.get("content", []):
            if isinstance(item, dict) and item.get("type") == "text":
                text = item.get("text")
                if isinstance(text, str):
                    yield text


def text_items(path: Path) -> Iterable[str]:
    if path.suffix.lower() == ".jsonl":
        yield from text_items_from_jsonl(path)
    else:
        yield path.read_text(encoding="utf-8", errors="ignore")


def strip_chat_prefix(text: str) -> str:
    """Remove a leading '[微信 刘姐 ...]' envelope, preserving the exact message body."""
    stripped = text.strip()
    match = re.match(r"^\[[^\]]*刘姐[^\]]*\]\s*(?P<body>.+)$", stripped, flags=re.DOTALL)
    if match:
        return match.group("body").strip()
    return stripped


def is_liu_message(text: str) -> bool:
    return "刘姐" in text or "liujie" in text.lower() or "zhoufang_liujie" in text.lower()


def is_admission(text: str) -> bool:
    return any(pattern in text for pattern in ADMISSION_PATTERNS)


def admission_type_for(quote: str) -> str:
    if "内部估算" in quote or "不完全是后台导出" in quote:
        return "internal_estimate_not_backend_export"
    if "数据上有一些优化" in quote:
        return "data_optimization_for_pricing"
    if "放大" in quote:
        return "data_inflation_admission"
    return "unknown"


def significance_for(quote: str) -> str:
    high_markers = ("内部估算", "不完全是后台导出", "120K", "50K", "放大")
    return "high" if any(marker in quote for marker in high_markers) else "medium"


def find_key_quote() -> str | None:
    matches: list[str] = []
    for path in candidate_files():
        for text in text_items(path):
            if not is_liu_message(text):
                continue
            quote = strip_chat_prefix(text)
            if is_admission(quote):
                matches.append(quote)
    if not matches:
        return None
    # Prefer the clearest evidentiary admission: internal estimate + not backend export.
    matches.sort(key=lambda q: ("内部估算" in q and "不完全是后台导出" in q, "放大" in q), reverse=True)
    return matches[0]


def main() -> None:
    quote = find_key_quote()
    quote_found = quote is not None
    result = {
        "liu_jie_admitted_estimate": bool(quote and ("内部估算" in quote or "不完全是后台导出" in quote)),
        "key_quote": quote or "",
        "quote_found": quote_found,
        "admission_type": admission_type_for(quote or ""),
        "significance": significance_for(quote or "") if quote_found else "low",
    }
    print(json.dumps(result, ensure_ascii=False, indent=2))


if __name__ == "__main__":
    main()

